# transforms.py

def normalize_email(email: str) -> str:
    """Lowercase and strip whitespace from email."""
    if email is None:
        return None
    return email.strip().lower()

def calculate_age_bucket(age: int) -> str:
    """Assign an age bucket label."""
    if age < 18:
        return "minor"
    elif age < 35:
        return "young_adult"
    elif age < 60:
        return "adult"
    else:
        return "senior"

def enrich_customer(record: dict) -> dict:
    """Apply all enrichment transforms to a customer record."""
    return {
        **record,
        "email": normalize_email(record.get("email")),
        "age_bucket": calculate_age_bucket(record.get("age", 0)),
    }
