import pytest
from transforms import normalize_email, calculate_age_bucket, enrich_customer

class TestNormalizeEmail:
    def test_lowercases_input(self):
        assert normalize_email("USER@EXAMPLE.COM") == "user@example.com"

    def test_strips_whitespace(self):
        assert normalize_email("  user@example.com  ") == "user@example.com"

    def test_handles_none(self):
        assert normalize_email(None) is None

    def test_already_normalized_is_unchanged(self):
        email = "user@example.com"
        assert normalize_email(email) == email

class TestCalculateAgeBucket:
    def test_minor_boundary(self):
        assert calculate_age_bucket(17) == "minor"
        assert calculate_age_bucket(18) == "young_adult"  # boundary belongs to next bucket

    def test_senior(self):
        assert calculate_age_bucket(60) == "senior"
        assert calculate_age_bucket(59) == "adult"

    def test_young_adult_range(self):
        for age in [18, 25, 34]:
            assert calculate_age_bucket(age) == "young_adult"

class TestEnrichCustomer:
    def test_enriches_full_record(self):
        record = {"id": 1, "email": "JOHN@EXAMPLE.COM", "age": 25}
        result = enrich_customer(record)
        assert result["email"] == "john@example.com"
        assert result["age_bucket"] == "young_adult"
        assert result["id"] == 1  # original fields preserved

    def test_handles_missing_email(self):
        record = {"id": 2, "age": 30}
        result = enrich_customer(record)
        assert result["email"] is None

