import pandas as pd

def remove_duplicates(df: pd.DataFrame, key_cols: list) -> pd.DataFrame:
    """Remove duplicate rows based on key columns, keeping first occurrence."""
    return df.drop_duplicates(subset=key_cols, keep="first").reset_index(drop=True)

def fill_missing_revenue(df: pd.DataFrame) -> pd.DataFrame:
    """Fill null revenue values with 0."""
    df = df.copy()
    df["revenue"] = df["revenue"].fillna(0.0)
    return df

def filter_active_customers(df: pd.DataFrame) -> pd.DataFrame:
    """Keep only active customers."""
    return df[df["status"] == "active"].reset_index(drop=True)
