import pytest
import pandas as pd
from pandas.testing import assert_frame_equal
from dataframe_transforms import remove_duplicates, fill_missing_revenue, filter_active_customers

@pytest.fixture
def customer_df():
    return pd.DataFrame({
        "id": [1, 2, 2, 3],
        "name": ["Alice", "Bob", "Bob", "Carol"],
        "revenue": [100.0, None, 200.0, 300.0],
        "status": ["active", "active", "active", "inactive"],
    })

class TestRemoveDuplicates:
    def test_removes_duplicate_ids(self, customer_df):
        result = remove_duplicates(customer_df, key_cols=["id"])
        assert len(result) == 3
        assert list(result["id"]) == [1, 2, 3]

    def test_keeps_first_occurrence(self, customer_df):
        result = remove_duplicates(customer_df, key_cols=["id"])
        # Bob's first row has revenue=None, not 200.0
        bob_row = result[result["id"] == 2]
        assert pd.isna(bob_row["revenue"].iloc[0])

    def test_no_duplicates_unchanged(self):
        df = pd.DataFrame({"id": [1, 2, 3], "val": [10, 20, 30]})
        result = remove_duplicates(df, key_cols=["id"])
        assert_frame_equal(result, df)

class TestFillMissingRevenue:
    def test_fills_nulls_with_zero(self, customer_df):
        result = fill_missing_revenue(customer_df)
        assert result["revenue"].isna().sum() == 0
        assert result.loc[1, "revenue"] == 0.0

    def test_does_not_modify_original(self, customer_df):
        fill_missing_revenue(customer_df)
        assert pd.isna(customer_df.loc[1, "revenue"])  # original unchanged

class TestFilterActiveCustomers:
    def test_keeps_only_active(self, customer_df):
        result = filter_active_customers(customer_df)
        assert all(result["status"] == "active")

    def test_correct_row_count(self, customer_df):
        result = filter_active_customers(customer_df)
        assert len(result) == 3  # Carol is inactive and removed

