import pandas as pd
from typing import Optional

class DataQualityError(Exception):
    """Raised when a data quality assertion fails."""
    pass

def assert_no_nulls(df: pd.DataFrame, columns: list, label: str = "") -> None:
    """Assert that specified columns have no null values."""
    for col in columns:
        null_count = df[col].isna().sum()
        if null_count > 0:
            raise DataQualityError(
                f"[{label}] Column '{col}' has {null_count} null values "
                f"({null_count / len(df):.1%} of rows)"
            )

def assert_unique(df: pd.DataFrame, columns: list, label: str = "") -> None:
    """Assert that specified columns (or combination) are unique."""
    duplicate_count = df.duplicated(subset=columns).sum()
    if duplicate_count > 0:
        raise DataQualityError(
            f"[{label}] Columns {columns} have {duplicate_count} duplicate rows"
        )

def assert_row_count_in_range(
    df: pd.DataFrame,
    min_rows: int,
    max_rows: Optional[int] = None,
    label: str = ""
) -> None:
    """Assert row count is within expected bounds."""
    actual = len(df)
    if actual < min_rows:
        raise DataQualityError(
            f"[{label}] Expected at least {min_rows} rows, got {actual}"
        )
    if max_rows is not None and actual > max_rows:
        raise DataQualityError(
            f"[{label}] Expected at most {max_rows} rows, got {actual}"
        )

def assert_values_in_set(
    df: pd.DataFrame,
    column: str,
    allowed_values: set,
    label: str = ""
) -> None:
    """Assert a column only contains values from an allowed set."""
    invalid = df[~df[column].isin(allowed_values)][column].unique()
    if len(invalid) > 0:
        raise DataQualityError(
            f"[{label}] Column '{column}' contains unexpected values: {list(invalid)}"
        )

def assert_column_range(
    df: pd.DataFrame,
    column: str,
    min_val=None,
    max_val=None,
    label: str = ""
) -> None:
    """Assert a numeric column's values are within [min_val, max_val]."""
    if min_val is not None:
        violations = df[df[column] < min_val]
        if len(violations) > 0:
            raise DataQualityError(
                f"[{label}] Column '{column}' has {len(violations)} values below {min_val}"
            )
    if max_val is not None:
        violations = df[df[column] > max_val]
        if len(violations) > 0:
            raise DataQualityError(
                f"[{label}] Column '{column}' has {len(violations)} values above {max_val}"
            )

def assert_schema(df: pd.DataFrame, expected_schema: dict, label: str = "") -> None:
    """
    Assert DataFrame has expected columns with expected dtypes.
    expected_schema: {"column_name": "dtype_string"}
    e.g., {"id": "int64", "revenue": "float64", "name": "object"}
    """
    for col, expected_dtype in expected_schema.items():
        if col not in df.columns:
            raise DataQualityError(
                f"[{label}] Expected column '{col}' not found in DataFrame"
            )
        actual_dtype = str(df[col].dtype)
        if actual_dtype != expected_dtype:
            raise DataQualityError(
                f"[{label}] Column '{col}' expected dtype '{expected_dtype}', "
                f"got '{actual_dtype}'"
            )
