import pytest
import pandas as pd
from data_assertions import (
    assert_no_nulls, assert_unique, assert_row_count_in_range,
    assert_values_in_set, assert_column_range, assert_schema, DataQualityError
)

@pytest.fixture
def clean_df():
    return pd.DataFrame({
        "id": [1, 2, 3],
        "revenue": [100.0, 200.0, 300.0],
        "status": ["active", "active", "inactive"],
    })

class TestAssertNoNulls:
    def test_passes_when_no_nulls(self, clean_df):
        assert_no_nulls(clean_df, ["id", "revenue"])  # should not raise

    def test_raises_when_nulls_exist(self):
        df = pd.DataFrame({"id": [1, None, 3], "val": [10, 20, 30]})
        with pytest.raises(DataQualityError, match="null values"):
            assert_no_nulls(df, ["id"])

class TestAssertUnique:
    def test_passes_when_unique(self, clean_df):
        assert_unique(clean_df, ["id"])  # should not raise

    def test_raises_when_duplicates_exist(self):
        df = pd.DataFrame({"id": [1, 1, 2]})
        with pytest.raises(DataQualityError, match="duplicate rows"):
            assert_unique(df, ["id"])

class TestAssertValuesInSet:
    def test_passes_when_all_valid(self, clean_df):
        assert_values_in_set(clean_df, "status", {"active", "inactive"})

    def test_raises_on_unexpected_value(self, clean_df):
        df = clean_df.copy()
        df.loc[0, "status"] = "pending"
        with pytest.raises(DataQualityError, match="unexpected values"):
            assert_values_in_set(df, "status", {"active", "inactive"})

class TestAssertColumnRange:
    def test_passes_within_range(self, clean_df):
        assert_column_range(clean_df, "revenue", min_val=0)

    def test_raises_below_minimum(self):
        df = pd.DataFrame({"revenue": [100.0, -50.0, 200.0]})
        with pytest.raises(DataQualityError, match="values below"):
            assert_column_range(df, "revenue", min_val=0)

class TestAssertSchema:
    def test_passes_correct_schema(self, clean_df):
        assert_schema(clean_df, {"id": "int64", "revenue": "float64"})

    def test_raises_missing_column(self, clean_df):
        with pytest.raises(DataQualityError, match="not found"):
            assert_schema(clean_df, {"nonexistent": "int64"})

    def test_raises_wrong_dtype(self):
        df = pd.DataFrame({"id": ["1", "2", "3"]})  # string, not int
        with pytest.raises(DataQualityError, match="expected dtype"):
            assert_schema(df, {"id": "int64"})

