import pandas as pd
import requests

def fetch_exchange_rates(api_url: str) -> dict:
    """Fetch currency exchange rates from external API."""
    response = requests.get(api_url)
    response.raise_for_status()
    return response.json()["rates"]

def convert_currencies(df: pd.DataFrame, rates: dict, target_currency: str) -> pd.DataFrame:
    """Convert 'amount' column from USD to target currency using rates dict."""
    df = df.copy()
    rate = rates.get(target_currency)
    if rate is None:
        raise ValueError(f"No exchange rate found for {target_currency}")
    df["amount_converted"] = df["amount"] * rate
    df["currency"] = target_currency
    return df

def run_currency_pipeline(
    df: pd.DataFrame,
    api_url: str,
    target_currency: str
) -> pd.DataFrame:
    rates = fetch_exchange_rates(api_url)
    return convert_currencies(df, rates, target_currency)
