import pytest
from hypothesis import given, settings, strategies as st
from transforms import normalize_email, calculate_age_bucket

class TestEmailNormalizationProperties:
    @given(st.emails())
    def test_normalized_email_is_always_lowercase(self, email):
        result = normalize_email(email)
        if result is not None:
            assert result == result.lower()

    @given(st.emails())
    def test_normalizing_twice_is_same_as_once(self, email):
        """Idempotency: normalize(normalize(x)) == normalize(x)"""
        once = normalize_email(email)
        twice = normalize_email(once) if once else None
        assert once == twice

    @given(st.text(min_size=1))
    def test_stripped_result_has_no_leading_trailing_spaces(self, text):
        result = normalize_email(text)
        if result is not None:
            assert result == result.strip()

class TestAgeBucketProperties:
    @given(st.integers(min_value=0, max_value=120))
    def test_always_returns_a_known_bucket(self, age):
        result = calculate_age_bucket(age)
        assert result in {"minor", "young_adult", "adult", "senior"}

    @given(st.integers(min_value=0, max_value=17))
    def test_under_18_is_always_minor(self, age):
        assert calculate_age_bucket(age) == "minor"

    @given(st.integers(min_value=60))
    def test_60_and_over_is_always_senior(self, age):
        assert calculate_age_bucket(age) == "senior"

