import pandera as pa
from pandera import Column, DataFrameSchema, Check

transaction_schema = DataFrameSchema({
    "user_id": Column(int, nullable=False),
    "amount": Column(float, Check.greater_than_or_equal_to(0), nullable=True),
    "status": Column(str, Check.isin(["completed", "pending", "failed"])),
})

def validate_with_pandera(df):
    return transaction_schema.validate(df)  # raises SchemaError if invalid
